const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binary = item.binary || {};
  const json = item.json || {};
  for (const [key, file] of Object.entries(binary)) {
    const mimeType = file.mimeType || "";
    const fileName = file.fileName || "";
    const isXml = mimeType === "application/xml" || mimeType === "text/xml" || fileName.toLowerCase().endsWith(".xml");
    const isPdf = mimeType === "application/pdf" || fileName.toLowerCase().endsWith(".pdf");

    if (isXml) {
      const buffer = await this.helpers.getBinaryDataBuffer(i, key);
      const xmlText = buffer.toString("utf8");
      out.push({
        json: {
          gmailMessageId: json.id,
          originalSubject: json.subject,
          attachmentKey: key,
          fileName,
          mimeType,
          contentKind: "xml_text",
          xmlText,
        },
      });
    } else if (isPdf) {
      out.push({
        json: {
          gmailMessageId: json.id,
          originalSubject: json.subject,
          attachmentKey: key,
          fileName,
          mimeType,
          contentKind: "upload_file",
        },
        binary: { data: file },
      });
    } else {
      out.push({
        json: {
          gmailMessageId: json.id,
          originalSubject: json.subject,
          attachmentKey: key,
          fileName,
          mimeType,
          contentKind: "unsupported",
        },
      });
    }
  }
}
return out;

return $input.all().map(item => ({
  json: {
    gmailMessageId: item.json.gmailMessageId,
    originalSubject: item.json.originalSubject,
    attachmentKey: item.json.attachmentKey,
    fileName: item.json.fileName,
    mimeType: item.json.mimeType,
    contentKind: "uploaded_file",
    uploadedFileId: item.json.id
  }
}));

const items = $input.all();

return [{
  json: {
    gmailMessageId: items[0].json.gmailMessageId,
    originalSubject: items[0].json.originalSubject,
    uploadedFiles: items
      .filter(item => item.json.contentKind === "uploaded_file")
      .map(item => ({
        fileId: item.json.uploadedFileId,
        fileName: item.json.fileName,
        mimeType: item.json.mimeType,
      })),
    xmlFiles: items
      .filter(item => item.json.contentKind === "xml_text")
      .map(item => ({
        fileName: item.json.fileName,
        mimeType: item.json.mimeType,
        xmlText: item.json.xmlText,
      })),
  }
}];

function removeNullish(value) {
  if (Array.isArray(value)) {
    return value.map(removeNullish);
  }

  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value)
        .filter(([, v]) => v !== undefined && v !== null && v !== "")
        .map(([k, v]) => [k, removeNullish(v)])
    );
  }

  return value;
}

let raw = $json.content?.[0]?.text ?? "{}";

// remove accidental code fences if Claude still adds them
raw = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/, "")
  .trim();

const parsed = JSON.parse(raw);

return [{
  json: {
    found_invoice: parsed.found_invoice === true,
    reason: parsed.reason ?? "",
    relevantAttachmentKeys: parsed.relevantAttachmentKeys ?? [],
    invoiceData: removeNullish(parsed.invoiceData ?? {}),
  },
  binary: $input.item.binary
}];

const relevantKeys = $json.relevantAttachmentKeys || [];
const sourceBinary = $('Start').item.binary || {};

const keptBinary = Object.fromEntries(
  relevantKeys
    .filter((key) => sourceBinary[key])
    .map((key) => [key, sourceBinary[key]])
);

const invoiceData = { ...($json.invoiceData || {}) };
invoiceData.currencyCode = 208324612;

for (const key of ["invoiceDate", "entryDate", "receiptDate"]) {
  if (
    typeof invoiceData[key] === "string" &&
    /^\d{4}-\d{2}-\d{2}$/.test(invoiceData[key])
  ) {
    invoiceData[key] = `${invoiceData[key]}T00:00:00Z`;
  }
}

return [{
  json: {
    ...$json,
    invoiceData,
    relevantAttachmentKeys: relevantKeys,
  },
  binary: keptBinary,
}];
